// ── Fox image ──
document.getElementById('foxLayer').style.backgroundImage = "url('data:image/png;base64,')";

// ── Star canvas (visible only in dark space top-left) ──
const sc = document.getElementById('starCanvas');
const sctx = sc.getContext('2d');
let SW, SH, stars = [];
function rsz() { SW = sc.width = window.innerWidth; SH = sc.height = window.innerHeight; }
function mkStars() {
  stars = Array.from({length: 220}, () => ({
    x: Math.random() * SW * 0.5,
    y: Math.random() * SH * 0.5,
    r: Math.random() * 1.2 + 0.15,
    a: Math.random() * Math.PI * 2,
    spd: Math.random() * 0.3 + 0.05
  }));
}
function drawStars() {
  sctx.clearRect(0, 0, SW, SH);
  stars.forEach(s => {
    s.a += s.spd * 0.012;
    const alpha = (Math.sin(s.a) + 1) / 2 * 0.75;
    sctx.beginPath();
    sctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
    sctx.fillStyle = `rgba(200,225,255,${alpha})`;
    sctx.fill();
  });
  requestAnimationFrame(drawStars);
}
rsz(); mkStars(); drawStars();

// ── Ambient floating particles ──
const pc = document.getElementById('bgCanvas');
const pctx = pc.getContext('2d');
let PW, PH, particles = [];
function prsz() { PW = pc.width = window.innerWidth; PH = pc.height = window.innerHeight; }
function mkPart() {
  particles = Array.from({length: 35}, () => ({
    x: Math.random() * PW,
    y: Math.random() * PH,
    vx: (Math.random() - 0.5) * 0.25,
    vy: -(Math.random() * 0.4 + 0.1),
    r: Math.random() * 1.8 + 0.4,
    a: Math.random(),
    life: Math.random()
  }));
}
function drawPart() {
  pctx.clearRect(0, 0, PW, PH);
  particles.forEach(p => {
    p.x += p.vx; p.y += p.vy; p.life -= 0.003;
    if (p.life <= 0) { p.life = 1; p.x = Math.random() * PW; p.y = PH + 10; }
    const alpha = Math.min(p.life, 1 - p.life) * 0.5;
    pctx.beginPath();
    pctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
    const c = Math.random() > 0.6 ? `rgba(232,144,26,${alpha * 0.6})` : `rgba(0,212,232,${alpha})`;
    pctx.fillStyle = c;
    pctx.fill();
  });
  requestAnimationFrame(drawPart);
}
prsz(); mkPart(); drawPart();

window.addEventListener('resize', () => { rsz(); mkStars(); prsz(); mkPart(); });

// ── Password toggle ──
function togglePass() {
  const inp = document.getElementById('pass');
  const icon = document.getElementById('eyeIcon');
  if (inp.type === 'password') {
    inp.type = 'text';
    icon.innerHTML = '<path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/>';
  } else {
    inp.type = 'password';
    icon.innerHTML = '<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>';
  }
}

// ── Checkbox ──
let checked = false;
function toggleCheck() {
  checked = !checked;
  const cb = document.getElementById('checkBox');
  cb.innerHTML = checked ? '✓' : '';
  cb.style.borderColor = checked ? 'var(--cyan)' : '';
  cb.style.background = checked ? 'rgba(0,212,232,0.12)' : '';
  cb.style.color = checked ? 'var(--cyan)' : '';
  cb.style.fontSize = '9px';
  cb.style.display = 'flex';
  cb.style.alignItems = 'center';
  cb.style.justifyContent = 'center';
}

// ── Login ──
function handleLogin(btn) {
  const orig = btn.textContent;
  btn.innerHTML = '<span style="display:inline-flex;align-items:center;gap:8px"><span style="display:inline-block;width:14px;height:14px;border:2px solid rgba(0,0,0,0.3);border-top-color:#040e1a;border-radius:50%;animation:spin 0.6s linear infinite"></span> Verificando…</span>';
  const style = document.createElement('style');
  style.textContent = '@keyframes spin { to { transform: rotate(360deg); } }';
  document.head.appendChild(style);
  btn.disabled = true;
  setTimeout(() => {
    btn.innerHTML = '✓ &nbsp;Acceso concedido';
    btn.style.background = 'linear-gradient(90deg,#28e080,#1fc870)';
    btn.style.boxShadow = '0 8px 32px rgba(40,224,128,0.4)';
    setTimeout(() => {
      btn.innerHTML = orig;
      btn.style.background = '';
      btn.style.boxShadow = '';
      btn.disabled = false;
    }, 2200);
  }, 1500);
}

// Expose functions to global scope for HTML inline handlers
if (typeof togglePass === 'function') window.togglePass = togglePass;
if (typeof toggleCheck === 'function') window.toggleCheck = toggleCheck;
if (typeof handleLogin === 'function') window.handleLogin = handleLogin;
